      "id": "job_1kpbj5u",
      "title": "Campus Quantitative Researcher, PhD (Intern)",
      "company": "Jump Trading",
      "location": "Chicago; New York",
      "posted_at": "2026-07-08T17:36:25-04:00",
      "posted_human": "13d ago",
      "url": "https://www.jumptrading.com/hr/job?gh_jid=8049938",
      "salary": "",
